import React, { useState, useRef, useEffect } from "react";
import Sidebar from "../components/Sidebar";
import { useAuth } from "../context/AuthContext";

const STARTERS = [
  "How do I become a Data Scientist?",
  "What skills are trending in 2025?",
  "How to prepare for a Google interview?",
  "Difference between React and Angular?",
  "What is a good salary for a fresher developer?",
  "How long does it take to learn Machine Learning?",
];

const SYSTEM_PROMPT = `You are SkillGraph AI — a friendly and knowledgeable career guidance assistant for Computer Science students and fresh graduates, especially in India and globally.

You help students with:
- Career path advice (which role suits their skills)
- Skill gap analysis and learning roadmaps
- Interview preparation tips
- Trending technologies and salaries
- Resume and LinkedIn tips
- Internship and job search strategies
- Comparing career paths (Data Science vs ML Engineering, etc.)

Be concise, practical, encouraging, and specific. Use bullet points and structure where helpful.
Tailor advice for students in India when relevant (companies like TCS, Infosys, Flipkart, Zomato, Razorpay, etc.).
When you mention salary, give both Indian (₹) and global (USD) context.`;

export default function Assistant() {
  const { user } = useAuth();
  const [messages, setMessages] = useState([
    {
      role: "assistant",
      content: `Hi ${user?.name?.split(" ")[0] || "there"}! 👋 I'm your AI Career Assistant, powered by Claude.\n\nI can help you with career paths, skill advice, interview prep, salary insights, and more. What would you like to know?`
    }
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const bottomRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages]);

  const send = async (text) => {
    const msg = text || input.trim();
    if (!msg || loading) return;
    setInput("");
    setError("");

    const newMessages = [...messages, { role: "user", content: msg }];
    setMessages(newMessages);
    setLoading(true);

    try {
      const apiMessages = newMessages.map(m => ({ role: m.role, content: m.content }));

      // Call backend proxy to avoid CORS (backend has ANTHROPIC_API_KEY)
      const token = localStorage.getItem("sg_token");
      const response = await fetch("/api/auth/ai/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
        body: JSON.stringify({ system: SYSTEM_PROMPT, messages: apiMessages }),
      });

      const data = await response.json();

      if (data.error) throw new Error(data.error.message);

      const reply = data.content?.find(c => c.type === "text")?.text || "Sorry, I couldn't generate a response.";
      setMessages(prev => [...prev, { role: "assistant", content: reply }]);
    } catch (e) {
      setError("⚠️ API error: " + e.message + " — Make sure you're running this via Claude.ai or with a valid API key.");
    } finally { setLoading(false); }
  };

  const formatMsg = (text) => {
    return text.split("\n").map((line, i) => {
      if (line.startsWith("**") && line.endsWith("**")) return <p key={i} style={{ fontWeight: 700, margin: "0 0 .3rem" }}>{line.slice(2, -2)}</p>;
      if (line.startsWith("• ") || line.startsWith("- ")) return <p key={i} style={{ margin: "0 0 .2rem", paddingLeft: "1rem" }}>• {line.slice(2)}</p>;
      if (line.match(/^\d+\. /)) return <p key={i} style={{ margin: "0 0 .2rem", paddingLeft: "1rem" }}>{line}</p>;
      if (line === "") return <br key={i} />;
      return <p key={i} style={{ margin: "0 0 .25rem" }}>{line}</p>;
    });
  };

  return (
    <div style={{ minHeight: "100vh", background: "var(--bg)", color: "var(--text)", display: "flex", flexDirection: "column" }}>
      <Sidebar/>
      <div style={{ maxWidth: 800, width: "100%", margin: "0 auto", padding: "1.5rem 1.5rem 0", flex: 1, display: "flex", flexDirection: "column" }}>
        <div style={{ marginBottom: "1rem" }}>
          <h1 className="sg-section-title" style={{ marginBottom: ".2rem" }}>🤖 AI Career Assistant</h1>
          <p style={{ color: "var(--muted)", fontSize: ".85rem" }}>Powered by Claude — ask anything about your tech career</p>
        </div>

        {/* Starters */}
        {messages.length <= 1 && (
          <div style={{ display: "flex", flexWrap: "wrap", gap: ".4rem", marginBottom: "1rem" }}>
            {STARTERS.map(s => (
              <button key={s} onClick={() => send(s)} style={{ background: "var(--bg3)", border: "1px solid var(--border)", borderRadius: 20, padding: ".35rem .8rem", fontSize: ".78rem", color: "var(--muted)", cursor: "pointer", transition: "all .2s" }}
                onMouseEnter={e => { e.target.style.borderColor = "var(--blue)"; e.target.style.color = "var(--blue)"; }}
                onMouseLeave={e => { e.target.style.borderColor = "var(--border)"; e.target.style.color = "var(--muted)"; }}>
                {s}
              </button>
            ))}
          </div>
        )}

        {/* Chat window */}
        <div style={{ flex: 1, overflowY: "auto", padding: ".5rem 0", marginBottom: "1rem", minHeight: 300, maxHeight: "calc(100vh - 380px)" }}>
          {messages.map((m, i) => (
            <div key={i} style={{ display: "flex", justifyContent: m.role === "user" ? "flex-end" : "flex-start", marginBottom: "1rem" }}>
              {m.role === "assistant" && (
                <div style={{ width: 32, height: 32, background: "linear-gradient(135deg,var(--blue),var(--purple))", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: ".9rem", marginRight: ".6rem", flexShrink: 0, marginTop: 4 }}>🤖</div>
              )}
              <div className={m.role === "user" ? "chat-bubble chat-me" : "chat-bubble chat-other"} style={{ maxWidth: "80%" }}>
                {m.role === "assistant" ? formatMsg(m.content) : m.content}
              </div>
              {m.role === "user" && (
                <div className="sg-avatar" style={{ width: 32, height: 32, fontSize: ".8rem", marginLeft: ".6rem", flexShrink: 0, marginTop: 4 }}>
                  {user?.name?.[0]?.toUpperCase() || "U"}
                </div>
              )}
            </div>
          ))}
          {loading && (
            <div style={{ display: "flex", alignItems: "center", gap: ".5rem", padding: ".5rem 0" }}>
              <div style={{ width: 32, height: 32, background: "linear-gradient(135deg,var(--blue),var(--purple))", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: ".9rem" }}>🤖</div>
              <div style={{ background: "var(--bg3)", border: "1px solid var(--border)", borderRadius: 14, padding: ".6rem 1rem" }}>
                <div style={{ display: "flex", gap: ".3rem" }}>
                  {[0, 1, 2].map(i => <div key={i} style={{ width: 6, height: 6, borderRadius: "50%", background: "var(--blue)", animation: "pulse 1.2s ease-in-out infinite", animationDelay: `${i * 0.2}s` }} />)}
                </div>
              </div>
            </div>
          )}
          {error && (
            <div style={{ background: "rgba(252,129,129,.08)", border: "1px solid rgba(252,129,129,.3)", borderRadius: 10, padding: ".8rem 1rem", color: "var(--red)", fontSize: ".82rem", marginBottom: ".5rem" }}>
              {error}
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        {/* Input */}
        <div style={{ position: "sticky", bottom: 0, background: "var(--bg)", paddingBottom: "1.5rem" }}>
          <div style={{ display: "flex", gap: ".6rem", background: "var(--bg2)", border: "1px solid var(--border)", borderRadius: 14, padding: ".6rem .6rem .6rem 1rem" }}>
            <input value={input} onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === "Enter" && !e.shiftKey && send()}
              placeholder="Ask about careers, skills, interviews, salaries..."
              style={{ flex: 1, background: "none", border: "none", outline: "none", color: "var(--text)", fontSize: ".9rem", fontFamily: "inherit" }} />
            <button onClick={() => send()} disabled={!input.trim() || loading} className="sg-btn sg-btn-primary" style={{ borderRadius: 10, padding: ".5rem 1rem" }}>
              Send →
            </button>
          </div>
          <p style={{ color: "var(--muted)", fontSize: ".72rem", textAlign: "center", marginTop: ".4rem" }}>
            Powered by Claude (Anthropic) · AI can make mistakes — verify important information
          </p>
        </div>
      </div>
    </div>
  );
}
